 */
scwin.acb_lc_odrDtNoGubun_onchange = function (info) {

    if (acb_lc_odrDtNoGubun.getValue() == "NO") {
        div_qryConKnd1.hide();
        div_qryConKnd2.show("");
    } else {
        div_qryConKnd1.show("");
        div_qryConKnd2.hide();
    };

};


